toolArgs.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_5efdc095a05d45a29295d9140d62a513.Models
@inject IApplicationService AppService

<PageTitle>Job Application</PageTitle>

<h2 class="mb-4">Job Application</h2>

<!-- Step Indicator Bar -->
<div class="step-indicator mb-4">
    @for (int i = 0; i < _stepNames.Length; i++)
    {
        var step = i + 1;
        var cssClass = step == _currentStep ? "active"
            : step < _currentStep ? "completed"
            : "future";
        <div class="step-item @cssClass"
             @onclick="() => GoToStep(step)"
             role="button"
             tabindex="0">
            <div class="step-circle">
                @if (step < _currentStep)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <div class="step-label">@_stepNames[step - 1]</div>
        </div>
        @if (step < _stepNames.Length)
        {
            <div class="step-connector @(step < _currentStep ? "completed" : "")"></div>
        }
    }
</div>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="alert alert-danger">@_errorMessage</div>
}

<!-- Step 1: Personal Info -->
@if (_currentStep == 1)
{
    <div class="card p-4">
        <h4>Personal Information</h4>
        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="_fullName" />
        </div>
        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" @bind="_email" />
        </div>
        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="_phone" />
        </div>
        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="_address" />
        </div>
        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="NextFromStep1" disabled="@_isValidating">
                @if (_isValidating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <span>Validating…</span>
                }
                else
                {
                    <span>Next</span>
                }
            </button>
        </div>
    </div>
}

<!-- Step 2: Work History -->
@if (_currentStep == 2)
{
    <div class="card p-4">
        <h4>Work History</h4>
        @for (int i = 0; i < _workEntries.Count; i++)
        {
            var index = i;
            var entry = _workEntries[index];
            <div class="border rounded p-3 mb-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="mb-0">Position @(index + 1)</h6>
                    @if (_workEntries.Count > 1)
                    {
                        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(index)">Remove</button>
                    }
                </div>
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Company Name <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@entry.Company"
                               @onchange="(e) => UpdateWork(index, entry with { Company = e.Value?.ToString() ?? string.Empty })" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@entry.Title"
                               @onchange="(e) => UpdateWork(index, entry with { Title = e.Value?.ToString() ?? string.Empty })" />
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
                        <input type="date" class="form-control" value="@entry.StartDate.ToString("yyyy-MM-dd")"
                               @onchange="(e) => UpdateWork(index, entry with { StartDate = DateTime.Parse(e.Value?.ToString() ?? DateTime.Today.ToString()) })" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? string.Empty)"
                               disabled="@entry.IsCurrent"
                               @onchange="(e) => UpdateWork(index, entry with { EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!) })" />
                    </div>
                    <div class="col-md-4 d-flex align-items-end pb-2">
                        <div class="form-check">
                            <input type="checkbox" class="form-check-input" id="current-@index" checked="@entry.IsCurrent"
                                   @onchange="(e) => UpdateWork(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                            <label class="form-check-label" for="current-@index">Currently working here</label>
                        </div>
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="2" value="@entry.Description"
                              @onchange="(e) => UpdateWork(index, entry with { Description = e.Value?.ToString() ?? string.Empty })"></textarea>
                </div>
            </div>
        }
        <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
            <button class="btn btn-primary" @onclick="NextFromStep2">Next</button>
        </div>
    </div>
}

<!-- Step 3: References -->
@if (_currentStep == 3)
{
    <div class="card p-4">
        <h4>References</h4>
        @for (int i = 0; i < _references.Count; i++)
        {
            var index = i;
            var r = _references[index];
            <div class="border rounded p-3 mb-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="mb-0">Reference @(index + 1)</h6>
                    @if (_references.Count > 1)
                    {
                        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                    }
                </div>
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Name <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@r.Name"
                               @onchange="(e) => UpdateRef(index, r with { Name = e.Value?.ToString() ?? string.Empty })" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Relationship <span class="text-danger">*</span></label>
                        <input type="text" class="form-control" value="@r.Relationship"
                               @onchange="(e) => UpdateRef(index, r with { Relationship = e.Value?.ToString() ?? string.Empty })" />
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control" value="@r.Email"
                               @onchange="(e) => UpdateRef(index, r with { Email = e.Value?.ToString() ?? string.Empty })" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Phone <span class="text-danger">*</span></label>
                        <input type="tel" class="form-control" value="@r.Phone"
                               @onchange="(e) => UpdateRef(index, r with { Phone = e.Value?.ToString() ?? string.Empty })" />
                    </div>
                </div>
            </div>
        }
        @if (_references.Count < 3)
        {
            <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
        }
        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
            <button class="btn btn-primary" @onclick="NextFromStep3">Next</button>
        </div>
    </div>
}

<!-- Step 4: Cover Letter -->
@if (_currentStep == 4)
{
    <div class="card p-4">
        <h4>Cover Letter</h4>
        <div class="mb-3">
            <textarea class="form-control" rows="10" maxlength="2000"
                      @bind="_coverLetter" @bind:event="oninput"></textarea>
            <div class="form-text text-end">@_coverLetter.Length / 2000 characters</div>
        </div>
        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
            <button class="btn btn-primary" @onclick="NextStep">Next</button>
        </div>
    </div>
}

<!-- Step 5: Review & Submit -->
@if (_currentStep == 5)
{
    @if (_submitted)
    {
        <div class="card p-4 text-center">
            <h4 class="text-success">&#10003; Application Submitted!</h4>
            <p class="fs-5">Your application ID is <strong>@_applicationId</strong></p>
            <p>Thank you for applying. We will review your application and get back to you.</p>
        </div>
    }
    else
    {
        <div class="card p-4">
            <h4>Review & Submit</h4>

            <!-- Personal Info Review -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h5>Personal Information</h5>
                    <button class="btn btn-link btn-sm" @onclick='() => GoToStep(1)'>Edit</button>
                </div>
                <dl class="row mb-0">
                    <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@_fullName</dd>
                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                </dl>
            </div>
            <hr />

            <!-- Work History Review -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h5>Work History</h5>
                    <button class="btn btn-link btn-sm" @onclick='() => GoToStep(2)'>Edit</button>
                </div>
                @foreach (var entry in _workEntries)
                {
                    <div class="border rounded p-2 mb-2">
                        <strong>@entry.Title</strong> at @entry.Company<br />
                        <small class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 mt-1">@entry.Description</p>
                        }
                    </div>
                }
            </div>
            <hr />

            <!-- References Review -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h5>References</h5>
                    <button class="btn btn-link btn-sm" @onclick='() => GoToStep(3)'>Edit</button>
                </div>
                @foreach (var r in _references)
                {
                    <div class="border rounded p-2 mb-2">
                        <strong>@r.Name</strong> (@r.Relationship)<br />
                        <small>@r.Email &middot; @r.Phone</small>
                    </div>
                }
            </div>
            <hr />

            <!-- Cover Letter Review -->
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h5>Cover Letter</h5>
                    <button class="btn btn-link btn-sm" @onclick='() => GoToStep(4)'>Edit</button>
                </div>
                <p style="white-space: pre-wrap;">@_coverLetter</p>
            </div>

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
                <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                    @if (_isSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        <span>Submitting…</span>
                    }
                    else
                    {
                        <span>Submit Application</span>
                    }
                </button>
            </div>
        </div>
    }
}

