+@code {
+    private static readonly string[] _stepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
+
+    private int _currentStep = 1;
+    private string _errorMessage = string.Empty;
+    private bool _isValidating;
+    private bool _isSubmitting;
+    private bool _submitted;
+    private int _applicationId;
+
+    // Step 1 fields
+    private string _fullName = string.Empty;
+    private string _email = string.Empty;
+    private string _phone = string.Empty;
+    private string _address = string.Empty;
+
+    // Step 2 fields
+    private List<WorkEntryModel> _workEntries = new() { new() };
+
+    // Step 3 fields
+    private List<ReferenceModel> _references = new() { new(), new() };
+
+    // Step 4 fields
+    private string _coverLetter = string.Empty;
+
+    // Mutable models for form binding
+    private class WorkEntryModel
+    {
+        public string Company { get; set; } = string.Empty;
+        public string Title { get; set; } = string.Empty;
+        public DateTime StartDate { get; set; } = DateTime.Today;
+        public DateTime? EndDate { get; set; }
+        public bool IsCurrent { get; set; }
+        public string Description { get; set; } = string.Empty;
+    }
+
+    private class ReferenceModel
+    {
+        public string Name { get; set; } = string.Empty;
+        public string Relationship { get; set; } = string.Empty;
+        public string Email { get; set; } = string.Empty;
+        public string Phone { get; set; } = string.Empty;
+    }
+
+    private void GoToStep(int step)
+    {
+        if (step < _currentStep)
+        {
+            _errorMessage = string.Empty;
+            _currentStep = step;
+        }
+    }
+
+    private void NextStep()
+    {
+        _errorMessage = string.Empty;
+        _currentStep++;
+    }
+
+    private void PreviousStep()
+    {
+        _errorMessage = string.Empty;
+        _currentStep--;
+    }
+
+    private async Task NextFromStep1()
+    {
+        _errorMessage = string.Empty;
+
+        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
+            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
+        {
+            _errorMessage = "All personal information fields are required.";
+            return;
+        }
+
+        _isValidating = true;
+        try
+        {
+            var isValid = await AppService.ValidateEmailAsync(_email);
+            if (!isValid)
+            {
+                _errorMessage = "Please enter a valid email address.";
+                return;
+            }
+            NextStep();
+        }
+        finally
+        {
+            _isValidating = false;
+        }
+    }
+
+    private void NextFromStep2()
+    {
+        _errorMessage = string.Empty;
+        foreach (var entry in _workEntries)
+        {
+            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
+            {
+                _errorMessage = "Company name and job title are required for each position.";
+                return;
+            }
+        }
+        NextStep();
+    }
+
+    private void NextFromStep3()
+    {
+        _errorMessage = string.Empty;
+        foreach (var r in _references)
+        {
+            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
+                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
+            {
+                _errorMessage = "All fields are required for each reference.";
+                return;
+            }
+        }
+        NextStep();
+    }
+
+    private void AddWorkEntry() => _workEntries.Add(new());
+    private void RemoveWorkEntry(int index) => _workEntries.RemoveAt(index);
+    private void UpdateWork(int index, WorkEntryModel entry) => _workEntries[index] = entry;
+
+    private void AddReference() { if (_references.Count < 3) _references.Add(new()); }
+    private void RemoveReference(int index) => _references.RemoveAt(index);
+    private void UpdateRef(int index, ReferenceModel r) => _references[index] = r;
+
+    private async Task SubmitApplication()
+    {
+        _isSubmitting = true;
+        _errorMessage = string.Empty;
+
+        try
+        {
+            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
+            var workHistory = new WorkHistory(_workEntries.Select(e =>
+                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
+            var references = _references.Select(r =>
+                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
+            var application = new JobApplication(personal, workHistory, references, _coverLetter);
+
+            _applicationId = await AppService.SubmitApplicationAsync(application);
+            _submitted = true;
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Submission failed: {ex.Message}";
+        }
+        finally
+        {
+            _isSubmitting = false;
+        }
+    }
+}
