+        <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-primary" @onclick="NextFromStep2">Next</button>
+        </div>
+    </div>
+}
+
+<!-- Step 3: References -->
+@if (_currentStep == 3)
+{
+    <div class="card p-4">
+        <h4>References</h4>
+        @for (int i = 0; i < _references.Count; i++)
+        {
+            var index = i;
+            var r = _references[index];
+            <div class="border rounded p-3 mb-3">
+                <div class="d-flex justify-content-between align-items-center mb-2">
+                    <h6 class="mb-0">Reference @(index + 1)</h6>
+                    @if (_references.Count > 1)
+                    {
+                        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
+                    }
+                </div>
+                <div class="row mb-2">
+                    <div class="col-md-6">
+                        <label class="form-label">Name <span class="text-danger">*</span></label>
+                        <input type="text" class="form-control" value="@r.Name"
+                               @onchange="(e) => UpdateRef(index, r with { Name = e.Value?.ToString() ?? string.Empty })" />
+                    </div>
+                    <div class="col-md-6">
+                        <label class="form-label">Relationship <span class="text-danger">*</span></label>
+                        <input type="text" class="form-control" value="@r.Relationship"
+                               @onchange="(e) => UpdateRef(index, r with { Relationship = e.Value?.ToString() ?? string.Empty })" />
+                    </div>
+                </div>
+                <div class="row mb-2">
+                    <div class="col-md-6">
+                        <label class="form-label">Email <span class="text-danger">*</span></label>
+                        <input type="email" class="form-control" value="@r.Email"
+                               @onchange="(e) => UpdateRef(index, r with { Email = e.Value?.ToString() ?? string.Empty })" />
+                    </div>
+                    <div class="col-md-6">
+                        <label class="form-label">Phone <span class="text-danger">*</span></label>
+                        <input type="tel" class="form-control" value="@r.Phone"
+                               @onchange="(e) => UpdateRef(index, r with { Phone = e.Value?.ToString() ?? string.Empty })" />
+                    </div>
+                </div>
+            </div>
+        }
+        @if (_references.Count < 3)
+        {
+            <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
+        }
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-primary" @onclick="NextFromStep3">Next</button>
+        </div>
+    </div>
+}
+
+<!-- Step 4: Cover Letter -->
+@if (_currentStep == 4)
+{
+    <div class="card p-4">
+        <h4>Cover Letter</h4>
+        <div class="mb-3">
+            <textarea class="form-control" rows="10" maxlength="2000"
+                      @bind="_coverLetter" @bind:event="oninput"></textarea>
+            <div class="form-text text-end">@_coverLetter.Length / 2000 characters</div>
+        </div>
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-primary" @onclick="NextStep">Next</button>
+        </div>
+    </div>
+}
+
+<!-- Step 5: Review & Submit -->
+@if (_currentStep == 5)
+{
+    @if (_submitted)
+    {
+        <div class="card p-4 text-center">
+            <h4 class="text-success">&#10003; Application Submitted!</h4>
+            <p class="fs-5">Your application ID is <strong>@_applicationId</strong></p>
+            <p>Thank you for applying. We will review your application and get back to you.</p>
+        </div>
+    }
+    else
+    {
+        <div class="card p-4">
+            <h4>Review & Submit</h4>
+
+            <!-- Personal Info Review -->
+            <div class="mb-4">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>Personal Information</h5>
+                    <button class="btn btn-link btn-sm" @onclick='() => GoToStep(1)'>Edit</button>
+                </div>
+                <dl class="row mb-0">
+                    <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@_fullName</dd>
+                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
+                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
+                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
+                </dl>
+            </div>
+            <hr />
+
+            <!-- Work History Review -->
+            <div class="mb-4">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>Work History</h5>
+                    <button class="btn btn-link btn-sm" @onclick='() => GoToStep(2)'>Edit</button>
+                </div>
+                @foreach (var entry in _workEntries)
+                {
+                    <div class="border rounded p-2 mb-2">
+                        <strong>@entry.Title</strong> at @entry.Company<br />
+                        <small class="text-muted">
+                            @entry.StartDate.ToString("MMM yyyy") –
+                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
+                        </small>
+                        @if (!string.IsNullOrWhiteSpace(entry.Description))
+                        {
+                            <p class="mb-0 mt-1">@entry.Description</p>
+                        }
+                    </div>
+                }
+            </div>
+            <hr />
+
+            <!-- References Review -->
+            <div class="mb-4">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>References</h5>
+                    <button class="btn btn-link btn-sm" @onclick='() => GoToStep(3)'>Edit</button>
+                </div>
+                @foreach (var r in _references)
+                {
+                    <div class="border rounded p-2 mb-2">
+                        <strong>@r.Name</strong> (@r.Relationship)<br />
+                        <small>@r.Email &middot; @r.Phone</small>
+                    </div>
+                }
+            </div>
+            <hr />
+
+            <!-- Cover Letter Review -->
+            <div class="mb-4">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>Cover Letter</h5>
+                    <button class="btn btn-link btn-sm" @onclick='() => GoToStep(4)'>Edit</button>
+                </div>
+                <p style="white-space: pre-wrap;">@_coverLetter</p>
+            </div>
+
+            <div class="d-flex justify-content-between">
+                <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+                <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
+                    @if (_isSubmitting)
+                    {
+                        <span class="spinner-border spinner-border-sm me-1"></span>
+                        <span>Submitting…</span>
+                    }
+                    else
+                    {
+                        <span>Submit Application</span>
+                    }
+                </button>
+            </div>
+        </div>
+    }
+}
+
+@code {
+    private static readonly string[] _stepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
+
+    private int _currentStep = 1;
+    private string _errorMessage = string.Empty;
+    private bool _isValidating;
+    private bool _isSubmitting;
+    private bool _submitted;
+    private int _applicationId;
+
+    // Step 1 fields
+    private string _fullName = string.Empty;
+    private string _email = string.Empty;
+    private string _phone = string.Empty;
+    private string _address = string.Empty;
+
+    // Step 2 fields
+    private List<WorkEntryModel> _workEntries = new() { new() };
+
+    // Step 3 fields
+    private List<ReferenceModel> _references = new() { new(), new() };
+
+    // Step 4 fields
+    private string _coverLetter = string.Empty;
+
+    // Mutable models for form binding
+    private class WorkEntryModel
+    {
+        public string Company { get; set; } = string.Empty;
+        public string Title { get; set; } = string.Empty;
+        public DateTime StartDate { get; set; } = DateTime.Today;
+        public DateTime? EndDate { get; set; }
+        public bool IsCurrent { get; set; }
+        public string Description { get; set; } = string.Empty;
+    }
+
+    private class ReferenceModel
+    {
+        public string Name { get; set; } = string.Empty;
+        public string Relationship { get; set; } = string.Empty;
+        public string Email { get; set; } = string.Empty;
+        public string Phone { get; set; } = string.Empty;
+    }
+
+    private void GoToStep(int step)
+    {
+        if (step < _currentStep)
+        {
+            _errorMessage = string.Empty;
+            _currentStep = step;
+        }
+    }
+
+    private void NextStep()
+    {
+        _errorMessage = string.Empty;
+        _currentStep++;
+    }
+
+    private void PreviousStep()
+    {
+        _errorMessage = string.Empty;
+        _currentStep--;
+    }
+
+    private async Task NextFromStep1()
+    {
+        _errorMessage = string.Empty;
+
+        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
+            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
+        {
+            _errorMessage = "All personal information fields are required.";
+            return;
+        }
+
+        _isValidating = true;
+        try
+        {
+            var isValid = await AppService.ValidateEmailAsync(_email);
+            if (!isValid)
+            {
+                _errorMessage = "Please enter a valid email address.";
+                return;
+            }
+            NextStep();
+        }
+        finally
+        {
+            _isValidating = false;
+        }
+    }
+
+    private void NextFromStep2()
+    {
+        _errorMessage = string.Empty;
+        foreach (var entry in _workEntries)
+        {
+            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
+            {
+                _errorMessage = "Company name and job title are required for each position.";
+                return;
+            }
+        }
+        NextStep();
+    }
+
+    private void NextFromStep3()
+    {
+        _errorMessage = string.Empty;
+        foreach (var r in _references)
+        {
+            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
+                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
+            {
+                _errorMessage = "All fields are required for each reference.";
+                return;
+            }
+        }
+        NextStep();
+    }
+
+    private void AddWorkEntry() => _workEntries.Add(new());
+    private void RemoveWorkEntry(int index) => _workEntries.RemoveAt(index);
+    private void UpdateWork(int index, WorkEntryModel entry) => _workEntries[index] = entry;
+
+    private void AddReference() { if (_references.Count < 3) _references.Add(new()); }
+    private void RemoveReference(int index) => _references.RemoveAt(index);
+    private void UpdateRef(int index, ReferenceModel r) => _references[index] = r;
+
+    private async Task SubmitApplication()
+    {
+        _isSubmitting = true;
+        _errorMessage = string.Empty;
+
+        try
+        {
+            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
+            var workHistory = new WorkHistory(_workEntries.Select(e =>
+                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
+            var references = _references.Select(r =>
+                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
+            var application = new JobApplication(personal, workHistory, references, _coverLetter);
+
+            _applicationId = await AppService.SubmitApplicationAsync(application);
+            _submitted = true;
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Submission failed: {ex.Message}";
+        }
+        finally
+        {
+            _isSubmitting = false;
+        }
+    }
+}
+

