.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    flex-wrap: wrap;
    gap: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    min-width: 90px;
}

.step-item.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-item.future .step-circle {
    border-color: #dee2e6;
    background: #f8f9fa;
    color: #adb5bd;
}

.step-label {
    font-size: 0.75rem;
    margin-top: 4px;
    text-align: center;
    color: #adb5bd;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    min-width: 20px;
    max-width: 60px;
    margin-bottom: 20px;
}

.step-connector.completed {
    background: #198754;
}

